<?php declare(strict_types=1); if (!defined('MNS_CONTROLLER_RENDER')) { require_once __DIR__ . '/../../../backend/controllers/timesheet_controller.php'; handleTimesheetRequest(); return; } require_once __DIR__ . '/../../../backend/includes/helpers.php'; require_once __DIR__ . '/../../../backend/includes/role_check.php'; $user = currentUser(); $flash = getFlashMessage(); $pages = max(1, (int) ceil(($total ?? 0) / ($perPage ?? 20))); $queryBase = $filters ?? []; require_once __DIR__ . '/../includes/header.php'; ?>
<div class="d-flex"><?php require_once __DIR__ . '/../includes/sidebar.php'; ?><main class="container-fluid py-4"><?php if ($flash): ?><div class="alert alert-<?php echo e($flash['type']==='success'?'success':'danger'); ?>"><?php echo e($flash['message']); ?></div><?php endif; ?><div class="d-flex justify-content-between align-items-center mb-3"><div><h1 class="h4 mb-1"><?php echo ($user['role'] ?? '') === 'EXPERT' ? 'Gestion des timesheets' : 'Mes timesheets'; ?></h1><div class="text-muted">Total filtre : <?php echo e(number_format((float)($totalHours ?? 0), 2, ',', ' ')); ?> h</div></div><div class="d-flex gap-2"><?php if (in_array(($user['role'] ?? ''), ['COLLABORATEUR','STAGIAIRE'], true)): ?><a class="btn btn-primary" href="/MNS_CORPORATE/frontend/views/timesheets/create.php">Ajouter</a><?php endif; ?><?php if (($user['role'] ?? '') === 'EXPERT'): ?><a class="btn btn-outline-secondary" href="/MNS_CORPORATE/frontend/views/timesheets/summary.php">Synthese</a><?php endif; ?></div></div>
<form class="row g-2 mb-3" method="get"><div class="col-md-3"><input class="form-control" name="q" value="<?php echo e($filters['q'] ?? ''); ?>" placeholder="Recherche description"></div><?php if (($user['role'] ?? '') === 'EXPERT'): ?><div class="col-md-2"><select class="form-select" name="user_id"><option value="">Tous utilisateurs</option><?php foreach (($users ?? []) as $u): ?><option value="<?php echo e((string)$u['id']); ?>" <?php echo (($filters['user_id'] ?? '') == $u['id']) ? 'selected' : ''; ?>><?php echo e($u['full_name']); ?></option><?php endforeach; ?></select></div><?php endif; ?><div class="col-md-2"><select class="form-select" name="mission_id"><option value="">Toutes missions</option><?php foreach (($missions ?? []) as $m): ?><option value="<?php echo e((string)$m['id']); ?>" <?php echo (($filters['mission_id'] ?? '') == $m['id']) ? 'selected' : ''; ?>><?php echo e($m['title']); ?></option><?php endforeach; ?></select></div><div class="col-md-2"><select class="form-select" name="status"><option value="">Tous statuts</option><?php foreach (Timesheet::STATUSES as $s): ?><option value="<?php echo e($s); ?>" <?php echo (($filters['status'] ?? '') === $s) ? 'selected' : ''; ?>><?php echo e($s); ?></option><?php endforeach; ?></select></div><div class="col-md-1"><input class="form-control" type="date" name="date_from" value="<?php echo e($filters['date_from'] ?? ''); ?>"></div><div class="col-md-1"><input class="form-control" type="date" name="date_to" value="<?php echo e($filters['date_to'] ?? ''); ?>"></div><div class="col-md-1"><button class="btn btn-outline-secondary w-100">Filtrer</button></div></form>
<div class="table-responsive bg-white border rounded"><table class="table table-hover align-middle mb-0"><thead class="table-light"><tr><th>Date</th><th>Utilisateur</th><th>Mission</th><th>Heures</th><th>Description</th><th>Statut</th><th class="text-end">Actions</th></tr></thead><tbody><?php foreach (($timesheets ?? []) as $t): ?><tr><td><?php echo e($t['work_date']); ?></td><td><?php echo e($t['user_name']); ?></td><td><?php echo e($t['mission_title']); ?></td><td><?php echo e((string)$t['hours_worked']); ?></td><td><?php echo e($t['description']); ?></td><td><span class="badge text-bg-<?php echo $t['status']==='VALIDE'?'success':($t['status']==='REFUSE'?'danger':'warning'); ?>"><?php echo e($t['status']); ?></span></td><td class="text-end"><a class="btn btn-sm btn-outline-primary" href="/MNS_CORPORATE/frontend/views/timesheets/show.php?id=<?php echo e((string)$t['id']); ?>">Voir</a><?php if (($user['role'] ?? '') === 'EXPERT' && $t['status'] === 'SAISI'): ?><form class="d-inline" method="post" action="/MNS_CORPORATE/frontend/views/timesheets/list.php?action=validate"><input type="hidden" name="id" value="<?php echo e((string)$t['id']); ?>"><button class="btn btn-sm btn-outline-success">Valider</button></form><form class="d-inline" method="post" action="/MNS_CORPORATE/frontend/views/timesheets/list.php?action=reject"><input type="hidden" name="id" value="<?php echo e((string)$t['id']); ?>"><button class="btn btn-sm btn-outline-danger">Refuser</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if (($timesheets ?? []) === []): ?><tr><td colspan="7" class="text-center text-muted py-4">Aucun timesheet.</td></tr><?php endif; ?></tbody></table></div>
<nav class="mt-3"><ul class="pagination"><?php for($i=1;$i<=$pages;$i++): $queryBase['page']=$i; ?><li class="page-item <?php echo $i===($page??1)?'active':''; ?>"><a class="page-link" href="?<?php echo e(http_build_query($queryBase)); ?>"><?php echo e((string)$i); ?></a></li><?php endfor; ?></ul></nav></main></div><?php require_once __DIR__ . '/../includes/footer.php'; ?>
